const raw = $json.content?.parts?.[0]?.text || "";

// raw might be a JSON string like: "{\"message\":\"...\"}"
let obj;

try {
  // First try: parse as JSON directly
  obj = JSON.parse(raw);
} catch (e1) {
  // If Gemini wrapped it in fences or extra text, clean then parse
  const cleaned = raw
    .replace(/```json\s*/i, "")
    .replace(/```/g, "")
    .trim();
  try {
    obj = JSON.parse(cleaned);
  } catch (e2) {
    throw new Error("Comms output not valid JSON. Raw: " + raw);
  }
}

return [{
  message: obj.message ?? ""
}];
